import React, { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import axios from "axios";
import Sidebar from "./Sidebar";
import Navbar from "./Navbar";
import "./Dashboard.css";
import {
    FaBuilding,
    FaUsers,
    FaFileContract,
    FaMoneyBillWave
} from "react-icons/fa";
import {
    Chart as ChartJS,
    ArcElement,
    Tooltip,
    Legend,
    CategoryScale,
    LinearScale,
    BarElement
} from "chart.js";

import { Pie, Bar } from "react-chartjs-2";

ChartJS.register(
    ArcElement,
    Tooltip,
    Legend,
    CategoryScale,
    LinearScale,
    BarElement
);

function Dashboard() {

    const [stats, setStats] = useState({
        properties: 0,
        tenants: 0,
        agreements: 0,
        payments: 0
    });

    useEffect(() => {
        fetchStats();
    }, []);

    const fetchStats = async () => {

        try {

            const token = localStorage.getItem("token");

            const response = await axios.get(
                "https://rental-management-system-backend-0h42.onrender.com/dashboard/stats",
                {
                    headers: {
                        Authorization: `Bearer ${token}`
                    }
                }
            );

            setStats(response.data);

        }
        catch (error) {

            console.log(error);

        }

    };

    const pieData = {
        labels: ["Payments", "Agreements"],
        datasets: [
            {
                data: [
                    stats.payments,
                    stats.agreements
                ],
                backgroundColor: [
                    "#36A2EB",
                    "#FFCE56"
                ]
            }
        ]
    };

    const barData = {
        labels: [
            "Properties",
            "Tenants",
            "Agreements",
            "Payments"
        ],
        datasets: [
            {
                label: "Count",
                data: [
                    stats.properties,
                    stats.tenants,
                    stats.agreements,
                    stats.payments
                ],
                backgroundColor: [
                    "#0d6efd",
                    "#198754",
                    "#ffc107",
                    "#0dcaf0"
                ]
            }
        ]
    };

    

}

export default Dashboard;
